struct Data(Vec<i32>);
impl IntoIterator for Data {
    type Item = i32;
    // Function pointers (fn) are not closures. A closure creates a unique anonymous type.
    // We use a Box<dyn Iterator> to erase the closure's specific type, or cast to a fn pointer.
    type IntoIter = std::iter::Filter<std::vec::IntoIter<i32>, fn(&i32) -> bool>;
    fn into_iter(self) -> Self::IntoIter {
        // explicitly cast the closure to a function pointer so it matches the signature
        self.0.into_iter().filter((|x| *x > 0) as fn(&i32) -> bool)
    }
}

